import os
import openai
from flask import Flask, request, jsonify
from werkzeug.security import safe_str_cmp

app = Flask(__name__)

# Load OpenAI API key from environment variable
openai.api_key = os.getenv("OPENAI_API_KEY")

# Define a simple allowlist for user input
ALLOWLIST = ["how can I", "what is", "help with", "support for"]

def is_input_valid(user_input):
    return any(user_input.lower().startswith(phrase) for phrase in ALLOWLIST)

@app.route('/chat', methods=['POST'])
def chat():
    user_input = request.json.get('message', '')

    if not is_input_valid(user_input):
        return jsonify({"error": "Invalid input"}), 400

    system_instructions = "You are a customer support assistant."
    prompt = f"{system_instructions} {user_input}"

    try:
        response = openai.ChatCompletion.create(
            model="gpt-3.5-turbo",
            messages=[{"role": "user", "content": prompt}]
        )
        return jsonify({"response": response['choices'][0]['message']['content']})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    app.run(port=5000)